apiVersion: policies.kyverno.io/v1
kind: MutatingPolicy
metadata:
  name: add-default-resources
  annotations:
    policies.kyverno.io/title: Add Default Resources
    policies.kyverno.io/category: Other
    policies.kyverno.io/severity: medium
    kyverno.io/kyverno-version: 1.17.0
    policies.kyverno.io/minversion: 1.17.0
    kyverno.io/kubernetes-version: "1.26"
    policies.kyverno.io/subject: Pod
    policies.kyverno.io/description: >-
      Pods which don't specify at least resource requests are assigned a QoS class
      of BestEffort which can hog resources for other Pods on Nodes. At a minimum,
      all Pods should specify resource requests in order to be labeled as the QoS
      class Burstable. This policy mutates any container in a Pod which doesn't
      specify memory or cpu requests to apply sane defaults.
spec:
  failurePolicy: Fail
  evaluation:
    admission:
      enabled: true
    mutateExisting:
      enabled: false
  matchConstraints:
    resourceRules:
      - apiGroups: ['']
        apiVersions: ['v1']
        operations: ['CREATE', 'UPDATE']
        resources: ['pods']
  variables:
    - name: allContainers
      expression: >-
        object.spec.containers
        + object.spec.?initContainers.orValue([])
        + object.spec.?ephemeralContainers.orValue([])
  mutations:
    # Patch containers
    - patchType: ApplyConfiguration
      applyConfiguration:
        expression: >
          Object{
            spec: Object.spec{
              containers: object.spec.containers.map(c,
                Object.spec.containers{
                  name: c.name,
                  resources: Object.spec.containers.resources{
                    requests: Object.spec.containers.resources.requests{
                      memory: (has(c.resources) && has(c.resources.requests) && has(c.resources.requests.memory))
                        ? c.resources.requests.memory
                        : "100Mi",
                      cpu: (has(c.resources) && has(c.resources.requests) && has(c.resources.requests.cpu))
                        ? c.resources.requests.cpu
                        : "100m"
                    }
                  }
                }
              )
            }
          }
    # Patch initContainers if present
    - patchType: ApplyConfiguration
      applyConfiguration:
        expression: >
          object.spec.?initContainers.orValue([]).size() > 0 ?
          Object{
            spec: Object.spec{
              initContainers: object.spec.initContainers.map(c,
                Object.spec.initContainers{
                  name: c.name,
                  resources: Object.spec.initContainers.resources{
                    requests: Object.spec.initContainers.resources.requests{
                      memory: (has(c.resources) && has(c.resources.requests) && has(c.resources.requests.memory))
                        ? c.resources.requests.memory
                        : "100Mi",
                      cpu: (has(c.resources) && has(c.resources.requests) && has(c.resources.requests.cpu))
                        ? c.resources.requests.cpu
                        : "100m"
                    }
                  }
                }
              )
            }
          }
          : Object{}
    # Patch ephemeralContainers if present
    - patchType: ApplyConfiguration
      applyConfiguration:
        expression: >
          object.spec.?ephemeralContainers.orValue([]).size() > 0 ?
          Object{
            spec: Object.spec{
              ephemeralContainers: object.spec.ephemeralContainers.map(c,
                Object.spec.ephemeralContainers{
                  name: c.name,
                  resources: Object.spec.ephemeralContainers.resources{
                    requests: Object.spec.ephemeralContainers.resources.requests{
                      memory: (has(c.resources) && has(c.resources.requests) && has(c.resources.requests.memory))
                        ? c.resources.requests.memory
                        : "100Mi",
                      cpu: (has(c.resources) && has(c.resources.requests) && has(c.resources.requests.cpu))
                        ? c.resources.requests.cpu
                        : "100m"
                    }
                  }
                }
              )
            }
          }
          : Object{}

