apiVersion: policies.kyverno.io/v1
kind: MutatingPolicy
metadata:
  name: inject-sidecar
  annotations:
    policies.kyverno.io/title: Inject Sidecar Container
    policies.kyverno.io/category: Sample
    policies.kyverno.io/subject: Deployment,Volume
    policies.kyverno.io/minversion: 1.17.0
    policies.kyverno.io/description: >-
      The sidecar pattern is very common in Kubernetes whereby other applications can
      insert components via tacit modification of a submitted resource. This is, for example,
      often how service meshes and secrets applications are able to function transparently.
      This policy injects a sidecar container, initContainer, and volume into Pods that match
      an annotation called `vault.hashicorp.com/agent-inject: true`.
spec:
  matchConstraints:
    resourceRules:
      - apiGroups: ["apps"]
        apiVersions: ["v1"]
        operations: ["CREATE", "UPDATE"]
        resources: ["deployments"]
  # Only mutate Deployments whose pod template carries the vault injection annotation.
  matchConditions:
    - name: has-vault-inject-annotation
      expression: >-
        has(object.spec.template.metadata.annotations) &&
        object.spec.template.metadata.annotations[?'vault.hashicorp.com/agent-inject'].orValue('') == 'true'
  mutations:
    # Append the vault-agent sidecar container to spec.template.spec.containers.
    - patchType: ApplyConfiguration
      applyConfiguration:
        expression: >-
          Object{
            spec: Object.spec{
              template: Object.spec.template{
                spec: Object.spec.template.spec{
                  containers:
                    object.spec.template.spec.containers +
                    (object.spec.template.spec.containers.exists(c, c.name == 'vault-agent') ? [] :
                    [Object.spec.template.spec.containers{
                      name: 'vault-agent',
                      image: 'vault:1.5.4',
                      imagePullPolicy: 'IfNotPresent',
                      volumeMounts: [Object.spec.template.spec.containers.volumeMounts{
                        mountPath: '/vault/secrets',
                        name: 'vault-secret'
                      }]
                    }])
                }
              }
            }
          }
    # Append the vault-agent-init initContainer to spec.template.spec.initContainers.
    - patchType: ApplyConfiguration
      applyConfiguration:
        expression: >-
          Object{
            spec: Object.spec{
              template: Object.spec.template{
                spec: Object.spec.template.spec{
                  initContainers:
                    object.spec.template.spec.?initContainers.orValue([]) +
                    (object.spec.template.spec.?initContainers.orValue([]).exists(c, c.name == 'vault-agent-init') ? [] :
                    [Object.spec.template.spec.initContainers{
                      name: 'vault-agent-init',
                      image: 'vault:1.5.4',
                      imagePullPolicy: 'IfNotPresent',
                      volumeMounts: [Object.spec.template.spec.initContainers.volumeMounts{
                        mountPath: '/vault/secrets',
                        name: 'vault-secret'
                      }]
                    }])
                }
              }
            }
          }
    # Append the vault-secret emptyDir volume to spec.template.spec.volumes.
    - patchType: ApplyConfiguration
      applyConfiguration:
        expression: >-
          Object{
            spec: Object.spec{
              template: Object.spec.template{
                spec: Object.spec.template.spec{
                  volumes:
                    object.spec.template.spec.?volumes.orValue([]) +
                    (object.spec.template.spec.?volumes.orValue([]).exists(v, v.name == 'vault-secret') ? [] :
                    [Object.spec.template.spec.volumes{
                      name: 'vault-secret',
                      emptyDir: Object.spec.template.spec.volumes.emptyDir{
                        medium: 'Memory'
                      }
                    }])
                }
              }
            }
          }

